int find_nth_number(int n) {
    if (n == 1) return 0;
    if (n == 2) return -1;
    if (n == 3) return -1;

    int a = 0, b = -1, c = -1;
    for (int i = 4; i <= n; ++i) {
        int next_number = a + b + c;
        a = b;
        b = c;
        c = next_number;
    }
    return c;
}

